import { Prisma } from '@prisma/client'
import { prisma } from '@wasp/prisma'

export const getTasks = async ({ overdueOnly }: { overdueOnly?: boolean }) => {
  const where: Prisma.TaskWhereInput = overdueOnly
    ? { dueDate: { lt: new Date() } }
    : {}

  return prisma.task.findMany({
    where,
    orderBy: { dueDate: 'asc' }
  })
}

