import { useState } from 'react'
import { useQuery, useAction } from '@wasp/queries'
import getTasks from '@src/queries'
import createTask from '@src/actions'
import './Main.css'

export function MainPage() {
  const [overdueOnly, setOverdueOnly] = useState(false)
  const [description, setDescription] = useState('')
  const [dueDate, setDueDate] = useState('')

  const { data: tasks = [], isLoading, refetch } = useQuery(getTasks, { overdueOnly })
  const createTaskFn = useAction(createTask)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!description || !dueDate) return

    try {
      await createTaskFn({ description, dueDate: new Date(dueDate) })
      setDescription('')
      setDueDate('')
      refetch()
    } catch (error) {
      console.error('Failed to create task:', error)
    }
  }

  const isOverdue = (taskDueDate: Date) => {
    return new Date(taskDueDate) < new Date()
  }

  if (isLoading) {
    return <div className="container">Loading tasks...</div>
  }

  return (
    <main className="container">
      <h1 className="title">Task Deadlines</h1>

      <div className="task-form">
        <h2>Add New Task</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label htmlFor="description">Description:</label>
            <input
              id="description"
              type="text"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Enter task description"
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="dueDate">Due Date:</label>
            <input
              id="dueDate"
              type="datetime-local"
              value={dueDate}
              onChange={(e) => setDueDate(e.target.value)}
              required
            />
          </div>
          <button type="submit" className="button button-filled">
            Add Task
          </button>
        </form>
      </div>

      <div className="task-list">
        <div className="task-header">
          <h2>Tasks</h2>
          <label className="toggle">
            <input
              type="checkbox"
              checked={overdueOnly}
              onChange={(e) => setOverdueOnly(e.target.checked)}
            />
            <span>Show Overdue Only</span>
          </label>
        </div>

        {tasks.length === 0 ? (
          <p className="empty-state">
            {overdueOnly ? 'No overdue tasks found.' : 'No tasks yet. Add one above!'}
          </p>
        ) : (
          <ul className="tasks">
            {tasks.map((task) => (
              <li key={task.id} className={`task ${isOverdue(task.dueDate) ? 'overdue' : ''}`}>
                <div className="task-content">
                  <strong>{task.description}</strong>
                  <span className={`task-date ${isOverdue(task.dueDate) ? 'overdue' : ''}`}>
                    Due: {new Date(task.dueDate).toLocaleString()}
                    {isOverdue(task.dueDate) && <span className="overdue-badge">OVERDUE</span>}
                  </span>
                </div>
              </li>
            ))}
          </ul>
        )}
      </div>
    </main>
  )
}

